import re
import json
from kafka import KafkaProducer
from kafka.errors import KafkaError
from flask import Flask, request, jsonify
from functools import wraps
import logging

app = Flask(__name__)
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

ALLOWED_TOPICS = {
    'user-events',
    'order-events',
    'notification-events',
    'analytics-events'
}

TOPIC_PATTERN = re.compile(r'^[a-zA-Z0-9._-]{1,249}$')

MAX_MESSAGE_SIZE = 1024 * 1024  # 1MB
RATE_LIMIT_PER_MINUTE = 100

rate_limit_store = {}

def validate_topic(topic):
    if not topic:
        return False, "Topic name cannot be empty"
    
    if not isinstance(topic, str):
        return False, "Topic name must be a string"
    
    if not TOPIC_PATTERN.match(topic):
        return False, "Topic name contains invalid characters or exceeds length limit"
    
    if topic not in ALLOWED_TOPICS:
        return False, f"Topic '{topic}' is not in the allowed topics list"
    
    return True, None

def validate_message(message):
    if not message:
        return False, "Message cannot be empty"
    
    if not isinstance(message, (str, dict)):
        return False, "Message must be a string or dictionary"
    
    try:
        if isinstance(message, dict):
            message_str = json.dumps(message)
        else:
            message_str = message
        
        if len(message_str.encode('utf-8')) > MAX_MESSAGE_SIZE:
            return False, f"Message size exceeds maximum allowed size of {MAX_MESSAGE_SIZE} bytes"
        
        return True, None
    except Exception as e:
        return False, f"Invalid message format: {str(e)}"

def check_rate_limit(client_id):
    import time
    current_time = int(time.time() / 60)
    
    if client_id not in rate_limit_store:
        rate_limit_store[client_id] = {'count': 0, 'window': current_time}
    
    if rate_limit_store[client_id]['window'] != current_time:
        rate_limit_store[client_id] = {'count': 0, 'window': current_time}
    
    if rate_limit_store[client_id]['count'] >= RATE_LIMIT_PER_MINUTE:
        return False
    
    rate_limit_store[client_id]['count'] += 1
    return True

def require_auth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_token = request.headers.get('Authorization')
        
        if not auth_token:
            return jsonify({'error': 'Missing authorization token'}), 401
        
        if not auth_token.startswith('Bearer '):
            return jsonify({'error': 'Invalid authorization format'}), 401
        
        token = auth_token.split(' ')[1]
        
        if not validate_auth_token(token):
            return jsonify({'error': 'Invalid or expired token'}), 403
        
        return f(*args, **kwargs)
    
    return decorated_function

def validate_auth_token(token):
    VALID_TOKENS = {
        'secure_token_123',
        'secure_token_456'
    }
    return token in VALID_TOKENS

try:
    producer = KafkaProducer(
        bootstrap_servers=['localhost:9092'],
        value_serializer=lambda v: json.dumps(v).encode('utf-8') if isinstance(v, dict) else v.encode('utf-8'),
        acks='all',
        retries=3,
        max_in_flight_requests_per_connection=1,
        security_protocol='SASL_SSL',
        sasl_mechanism='PLAIN',
        sasl_plain_username='kafka_user',
        sasl_plain_password='kafka_password',
        ssl_check_hostname=True,
        ssl_cafile='/path/to/ca-cert',
        api_version=(2, 5, 0)
    )
except Exception as e:
    logger.error(f"Failed to initialize Kafka producer: {str(e)}")
    producer = None

@app.route('/publish', methods=['POST'])
@require_auth
def publish_message():
    if producer is None:
        return jsonify({'error': 'Kafka producer not available'}), 503
    
    try:
        data = request.get_json()
        
        if not data:
            return jsonify({'error': 'Request body must be JSON'}), 400
        
        topic_name = data.get('topic')
        message = data.get('message')
        
        is_valid_topic, topic_error = validate_topic(topic_name)
        if not is_valid_topic:
            logger.warning(f"Invalid topic attempted: {topic_name}")
            return jsonify({'error': topic_error}), 400
        
        is_valid_message, message_error = validate_message(message)
        if not is_valid_message:
            return jsonify({'error': message_error}), 400
        
        client_id = request.headers.get('X-Client-ID', request.remote_addr)
        if not check_rate_limit(client_id):
            return jsonify({'error': 'Rate limit exceeded'}), 429
        
        future = producer.send(topic_name, message)
        
        try:
            record_metadata = future.get(timeout=10)
            
            logger.info(f"Message published to topic: {topic_name}, partition: {record_metadata.partition}, offset: {record_metadata.offset}")
            
            return jsonify({
                'status': 'success',
                'topic': topic_name,
                'partition': record_metadata.partition,
                'offset': record_metadata.offset
            }), 200
            
        except KafkaError as e:
            logger.error(f"Failed to publish message: {str(e)}")
            return jsonify({'error': 'Failed to publish message to Kafka'}), 500
            
    except json.JSONDecodeError:
        return jsonify({'error': 'Invalid JSON format'}), 400
    except Exception as e:
        logger.error(f"Unexpected error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/topics', methods=['GET'])
@require_auth
def get_allowed_topics():
    return jsonify({
        'allowed_topics': list(ALLOWED_TOPICS)
    }), 200

@app.route('/health', methods=['GET'])
def health_check():
    if producer is None:
        return jsonify({'status': 'unhealthy', 'kafka': 'disconnected'}), 503
    return jsonify({'status': 'healthy', 'kafka': 'connected'}), 200

@app.errorhandler(404)
def not_found(error):
    return jsonify({'error': 'Endpoint not found'}), 404

@app.errorhandler(500)
def internal_error(error):
    return jsonify({'error': 'Internal server error'}), 500

if __name__ == '__main__':
    app.run(host='127.0.0.1', port=5000, debug=False)